/**
 * Provides a utility function to determine whether a graphic's origin is a [OrientedImageryGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/OrientedImageryGraphicOrigin/).
 *
 * @since 5.0
 * @example
 * // Use hitTest() to get a graphic, then check whether it originated from a OrientedImageryLayer.
 * view.hitTest(screenPoint).then((response) => {
 *   const graphic = response.results[0]?.graphic;
 *   if (!graphic) {
 *     return;
 *   }
 *   if (isOrientedImageryGraphicOrigin(graphic.origin)) {
 *     // hitTest returned a graphic from a OrientedImageryLayer.
 *     // Use this info for your processing logic.
 *   } else {
 *     console.log("graphic's origin is NOT a OrientedImageryLayer");
 *   }
 * });
 */
import type GraphicOrigin from "./GraphicOrigin.js";
import type OrientedImageryGraphicOrigin from "./OrientedImageryGraphicOrigin.js";

/**
 * Utility function that determines whether a graphic’s origin is a [OrientedImageryGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/OrientedImageryGraphicOrigin/).
 *
 * @param origin - The graphic origin to check.
 * @returns Returns `true` if the graphic origin is of type [OrientedImageryGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/OrientedImageryGraphicOrigin/), `false` otherwise.
 */
export function isOrientedImageryGraphicOrigin(origin: GraphicOrigin | null | undefined): origin is OrientedImageryGraphicOrigin;